#include <iostream>
#include <fstream>
#include <vector>
#include <unordered_map>
#include <algorithm>

using namespace std;

// algoritmul pt sortare topologica rezolvat in solutiile oficiale ale
// laboratorului

void dfs(int node, vector<vector<int>> &adj, vector<int>& used,
    vector<int>& topsort) {
    used[node] = 1;  // marcheze nodul ca fiind vizitat

    // parcurg vecinii
    for (auto& neigh : adj[node]) {
        if (!used[neigh]) {
            dfs(neigh, adj, used, topsort);
        }
    }

    // dupa ce am vizitat recursiv toti vecinii, adaugam
    // nodul la sortare
    topsort.push_back(node);
}

int computeLongestPath(vector<int> topsort, vector<vector<int>> graph,
                       unordered_map<string, int> cities, int index,
                       string start, string end) {
    vector<int> longest_path(index, 0);
    longest_path[cities[start]] = 1;

    for (int node : topsort) {
        if (longest_path[node] != 0) {
            for (int neighbor : graph[node]) {
                if (longest_path[node] + 1 > longest_path[neighbor])
                    longest_path[neighbor] = longest_path[node] + 1;
            }
        }
    }

    return longest_path[cities[end]];
}

int main() {
    ifstream input_file("trenuri.in");
    string start, end, x, y;
    int M, index = 0;
    input_file >> start >> end;
    input_file >> M;

    unordered_map<string, int> cities;
    vector<vector<int>> graph;

    for (int i = 0; i < M; ++i) {
        input_file >> x >> y;
        if (cities.count(x) == 0) {
            cities[x] = index;
            graph.push_back({});
            index++;
        }

        if (cities.count(y) == 0) {
            cities[y] = index;
            graph.push_back({});
            index++;
        }

        graph[cities[x]].push_back(cities[y]);
    }

    vector<int> used(index, 0);
    vector<int> topsort;

    for (int node = 1; node <= index; ++node) {
        // daca nodul este nevizitat, pornim o parcurgere
        if (!used[node]) {
            dfs(node, graph, used, topsort);
        }
    }

    reverse(topsort.begin(), topsort.end());

    int max_cities = computeLongestPath(topsort, graph, cities, index, start,
                                        end);

    ofstream output_file("trenuri.out");
    output_file << max_cities;

    return 0;
}

import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;
import java.util.Stack;

public class Trenuri {
	MyScanner myScanner;
	String source;
	String destination;
	int M;

	// adjacency list of the graph as hash map
	HashMap<String, ArrayList<String>> adj;
	// map for dp table
	HashMap<String, Integer> dp;
	// map for visited cities
	HashMap<String, Boolean> visited;
	// set for all cities
	Set<String> cities;

	private void readInput() {
		try {
			myScanner = new MyScanner(new FileReader("trenuri.in"));
			// read input
			source = myScanner.next();
			destination = myScanner.next();
			M = myScanner.nextInt();

			// initialize adjacency list of the graph
			adj = new HashMap<>();
			cities = new HashSet<>();

			// read edges and build the graph
			for (int i = 0; i < M; i++) {
				String src = myScanner.next();
				String dest = myScanner.next();

				adj.computeIfAbsent(src, k -> new ArrayList<>()).add(dest);

				// Add nodes to cities set
				cities.add(src);
				cities.add(dest);
			}
			myScanner.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void writeOutput(int result) {
		try {
			PrintWriter pw = new PrintWriter("trenuri.out");
			pw.println(result);
			pw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void topologicalSort(String currentCity, Map<String, Boolean> visited,
		Map<String, ArrayList<String>> adj, Stack<String> stack) {
		// set current node as visited
		visited.put(currentCity, true);

		for (String neighbour : adj.getOrDefault(currentCity, new ArrayList<>())) {
			// check if neighbour was visited
			if (!visited.getOrDefault(neighbour, false)) {
				topologicalSort(neighbour, visited, adj, stack);
			}
		}

		// push current city to the stack
		stack.push(currentCity);
	}

	private int getLongestPath() {
		Stack<String> stack = new Stack<>();
		dp = new HashMap<>();
		visited = new HashMap<>();

		// call topological sort
		for (String city : cities) {
			// init dp table -> mark all cities as not visited
			dp.put(city, -1);
			if (!visited.getOrDefault(city, false)) {
				topologicalSort(city, visited, adj, stack);
			}
		}

		dp.put(source, 0);

		// get the longest path
		while (!stack.isEmpty()) {
			String node = stack.pop();

			// if the current city was visited
			if (dp.get(node) != -1) {
				for (String neighbour : adj.getOrDefault(node, new ArrayList<>())) {
					// Update the longest path to the neighbor node
					dp.put(neighbour, Math.max(dp.get(neighbour), dp.get(node) + 1));
				}
			}
		}

		// increment the result
		return dp.get(destination) + 1;
	}

	public static void main(String[] args) {
		Trenuri solution = new Trenuri();
		solution.readInput();
		int longestPath = solution.getLongestPath();
		solution.writeOutput(longestPath);
	}
}
